+  ///   MetaMethod method = ...;
+  ///   stream << method;
+  /// }
+  ///
+  /// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~/
+  class QI_API PrettyPrintStream
+  {
+  public:
+    enum class Option
+    {
+      Colorized      = 1 << 0,
+      Documentation  = 1 << 1,
+      RawSignatures  = 1 << 2
+    };
+    using Options = qi::Flags<Option>;
+
+    enum class RecurseOption : bool
+    {
+      DoNotRecurse = false,
+      Recurse = true,
+    };
